    private func fetchData(from urlString: String) {
        guard let url = URL(string: urlString) else {
            addResponse("Invalid URL: \(urlString)")
            return
        }
        
        let task = URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.addResponse("Error from \(urlString): \(error.localizedDescription)")
                    return
                }
                
                if let httpResponse = response as? HTTPURLResponse {
                    let statusMessage = "Status \(httpResponse.statusCode) from \(urlString)"
                    if let data = data, let dataString = String(data: data, encoding: .utf8) {
                        self?.addResponse("\(statusMessage)\nData: \(dataString.prefix(100))")
                    } else {
                        self?.addResponse(statusMessage)
                    }
                }
            }
        }
        task.resume()
        addResponse("Fetching from \(urlString)...")
    }
    
    private func addResponse(_ response: String) {
        responses.insert(response, at: 0)
        tableView.reloadData()
